class Solution {
    public long maxGCDScore(int[] nums, int k) {
        int n = nums.length;
        int[] gcds = new int[n];
        gcds[0] = nums[0];
        for (int i = 1; i < n; i++) {
            gcds[i] = gcd(gcds[i - 1], nums[i]);
        }
        long[] dp = new long[n];
        dp[0] = gcds[0];
        long maxScore = dp[0];
        for (int i = 1; i < n; i++) {
            dp[i] = Math.max(dp[i - 1], (i + 1) * gcds[i]);
            maxScore = Math.max(maxScore, dp[i]);
        }
        while (k-- > 0) {
            int maxIdx = -1;
            int maxVal = 0;
            for (int i = 0; i < n; i++) {
                if (nums[i] > maxVal) {
                    maxVal = nums[i];
                    maxIdx = i;
                }
            }
            nums[maxIdx] *= 2;
            gcds[0] = nums[0];
            for (int i = 1; i < n; i++) {
                gcds[i] = gcd(gcds[i - 1], nums[i]);
            }
            dp[0] = gcds[0];
            maxScore = dp[0];
            for (int i = 1; i < n; i++) {
                dp[i] = Math.max(dp[i - 1], (i + 1) * gcds[i]);
                maxScore = Math.max(maxScore, dp[i]);
            }
        }
        return maxScore;
    }

    private int gcd(int a, int b) {
        if (b == 0) {
            return a;
        }
        return gcd(b, a % b);
    }
}
